<template><div class="page-container" v-loading="loading"><section v-if="data.person" class="profile-detail"><div class="profile-portrait"><img v-if="data.person.avatarUrl" :src="data.person.avatarUrl"><div v-else class="avatar-placeholder large">{{ data.person.name?.[0] }}</div></div><div><p class="eyebrow">PERSON PROFILE</p><h1>{{ data.person.name }}</h1><div class="tag-row"><el-tag type="success">{{ data.person.country||'地区未知' }}</el-tag><el-tag v-if="data.person.birthday" effect="plain">{{ data.person.birthday }}</el-tag></div><p class="lead">{{ data.person.introduction||'暂无人物介绍。' }}</p></div></section><section class="section compact"><PageHeader title="参与作品"/><div class="simple-list"><router-link v-for="w in data.works||[]" :key="w.workId||w.id" :to="`/works/${w.workId||w.id}`">{{ w.workTitle||w.title||`作品 ${w.workId}` }}<span>{{ w.roleType||'' }}</span></router-link><EmptyState v-if="!data.works?.length"/></div></section></div></template>
<script setup>import { onMounted,reactive,ref } from 'vue';import { useRoute } from 'vue-router';import PageHeader from '../../components/PageHeader.vue';import EmptyState from '../../components/EmptyState.vue';import { personApi } from '../../api/person';const route=useRoute(),loading=ref(true),data=reactive({person:null,works:[]});onMounted(async()=>{Object.assign(data,await personApi.detail(route.params.id));loading.value=false})</script>
